package com.example.secondphone.config;
import org.slf4j.*;import org.springframework.beans.factory.annotation.Value;import org.springframework.boot.CommandLineRunner;import org.springframework.security.crypto.password.PasswordEncoder;import org.springframework.stereotype.Component;import com.example.secondphone.entity.*;import com.example.secondphone.repository.MemberRepository;
@Component public class AdminInitializer implements CommandLineRunner{private static final Logger log=LoggerFactory.getLogger(AdminInitializer.class);private final MemberRepository members;private final PasswordEncoder encoder;private final String email,password,username;public AdminInitializer(MemberRepository members,PasswordEncoder encoder,@Value("${app.admin.email:}")String email,@Value("${app.admin.password:}")String password,@Value("${app.admin.username:admin}")String username){this.members=members;this.encoder=encoder;this.email=email;this.password=password;this.username=username;}public void run(String...args){if(members.existsByRole(MemberRole.ADMIN))return;if(email.isBlank()||password.isBlank()){log.warn("尚未建立管理員：請設定 APP_ADMIN_EMAIL 與 APP_ADMIN_PASSWORD");return;}if(password.length()<8)throw new IllegalStateException("APP_ADMIN_PASSWORD 至少需要 8 個字元");Member m=new Member();m.setAccount(username);m.setEmail(email.toLowerCase());m.setPassword(encoder.encode(password));m.setName("系統管理員");m.setRole(MemberRole.ADMIN);m.setStatus(MemberStatus.ACTIVE);members.save(m);log.info("已建立初始管理員帳號：{}",email);}}
